 23	void is_on_changed(void *_d)
 24	{
 25	  vcd_data *d = _d;
 26	  char t;
 27	
 28	  if (pthread_mutex_lock(&d->lock)) abort();
 29	
 30	  if (d->socket == -1) goto no_connection;
 31	
 32	  t = 1;
 33	  if (socket_send(d->socket, &t, 1) == -1 ||
 34	      socket_send(d->socket, &d->nevents, sizeof(int)) == -1 ||
 35	      socket_send(d->socket, d->is_on, d->nevents * sizeof(int)) == -1)
 36	    abort();
 37	
 38	no_connection:
 39	  if (pthread_mutex_unlock(&d->lock)) abort();
 40	}
