 94	  w = new_timeline(g, 1000, nb_functions, 5);
 95	  widget_add_child(g, container, w, -1);
 96	  for (i = 0; i < nb_functions; i++)
 97	    timeline_set_subline_background_color(g, w, i,
 98	        new_color(g, i & 1 ? "#ddd" : "#eee"));
 99	  timeview = new_view_time(3600, 10, g, w);
100	  i = 0;
101	  for (j = 0; j < n; j++) {
102	    if (strncmp(ids[j], "VCD_FUNCTION_", 13) != 0) continue;
103	    timelog = new_timelog(h, database, ids[j]);
104	    subview = new_subview_time(timeview, i, FOREGROUND_COLOR, 3600*1000);
105	    logger_add_view(timelog, subview);
106	    i++;
107	  }
108	
109	  free(ids);
110	}
