178	
179	  vcd_data.socket = -1;
180	  vcd_data.is_on = is_on;
181	  vcd_data.nevents = number_of_events;
182	  if (pthread_mutex_init(&vcd_data.lock, NULL)) abort();
183	  setup_event_selector(g, database, is_on, is_on_changed, &vcd_data);
184	
